class InAppPurchaseProcessor(
    private val context: Context,
    private val secureStorage: SecureStorage
) {
    suspend fun launchPurchaseFlow(activity: Activity, request: PurchaseRequest): PaymentResult = withContext(Dispatchers.Main) {
        try {
            val transactionId = CryptoUtils.generateTransactionId()
            secureStorage.putString("pending_purchase_txn", transactionId)
            secureStorage.putString("pending_purchase_product", request.productId)
            secureStorage.putString("pending_purchase_user", request.userId)
            secureStorage.putString("pending_purchase_amount", request.amountCents.toString())
            secureStorage.putString("pending_purchase_currency", request.currency)

            val intent = Intent(activity, activity::class.java)
            activity.startActivity(intent)

            PaymentResult(
                success = true,
                transactionId = transactionId,
                message = "Purchase flow initiated"
            )
        } catch (t: Throwable) {
            PaymentResult(
                success = false,
                message = t.message ?: "Purchase failed",
                errorCode = "PURCHASE_INIT_ERROR"
            )
        }
    }

    suspend fun verifyAndFinalize(receipt: String): PaymentResult = withContext(Dispatchers.IO) {
        try {
            val verified = verifyReceiptLocally(receipt)
            if (!verified) {
                return@withContext PaymentResult(
                    success = false,
                    message = "Receipt verification failed",
                    errorCode = "RECEIPT_INVALID"
                )
            }

            val txnId = secureStorage.getString("pending_purchase_txn")
            secureStorage.remove("pending_purchase_txn")
            secureStorage.remove("pending_purchase_product")
            secureStorage.remove("pending_purchase_user")
            secureStorage.remove("pending_purchase_amount")
            secureStorage.remove("pending_purchase_currency")

            PaymentResult(
                success = true,
                transactionId = txnId,
                message = "Purchase completed"
            )
        } catch (t: Throwable) {
            PaymentResult(
                success = false,
                message = t.message ?: "Finalization failed",
                errorCode = "PURCHASE_FINALIZE_ERROR"
            )
        }
    }

    private fun verifyReceiptLocally(receipt: String): Boolean {
        return receipt.isNotBlank() && receipt.length > 20
    }
}

class WalletTransactionProcessor(
    private val secureStorage: SecureStorage
) {
    suspend fun process(request: WalletTransactionRequest): PaymentResult = withContext(Dispatchers.IO) {
        try {
            if (request.amountCents <= 0) {
                return@withContext PaymentResult(
                    success = false,
                    message = "Invalid amount",
                    errorCode = "INVALID_AMOUNT"
                )
            }

            val transactionId = CryptoUtils.generateTransactionId()
            val payload = buildString {
                append(request.walletId)
                append('|')
                append(request.userId)
                append('|')
                append(request.amountCents)
                append('|')
                append(request.currency)
                append('|')
                append(request.reference ?: "")
            }

            secureStorage.putString("last_wallet_txn", CryptoUtils.sha256(payload))
            secureStorage.putString("last_wallet_txn_id", transactionId)

            PaymentResult(
                success = true,
                transactionId = transactionId,
                message = "Wallet transaction processed"
            )
        } catch (t: Throwable) {
            PaymentResult(
                success = false,
                message = t.message ?: "Wallet transaction failed",
                errorCode = "WALLET_TXN_ERROR"
            )
        }
    }
}

